      align: 'right',
      render: v => Number(v).toLocaleString('vi-VN'),
    },
  ]

  const candKey = (r: Candidate) => `${r.loai}-${r.id}`
  const selectedCandKey = selectedCandidate ? candKey(selectedCandidate) : null

  return (
