            <Select
              style={{ width: 220 }}
              allowClear
              placeholder="Tài khoản ngân hàng"
              onChange={v => setBankAccountId(v)}
              options={(bankAccounts ?? []).map((a: BankAccount) => ({
                value: a.id,
                label: `${a.ten_ngan_hang} – ${a.so_tai_khoan}`,
