              title="Chưa khớp"
              value={tongChuaKhop}
              valueStyle={{ color: tongChuaKhop > 0 ? '#cf1322' : '#3f8600' }}
            />
          </Col>
          <Col>
            <Statistic
              title="Đã khớp"
              value={tongDaKhop}
              valueStyle={{ color: '#3f8600' }}
            />
          </Col>
        </Row>
      </Card>

