        {/* Left: Bank transactions */}
        <Col span={14}>
          <Card
            size="small"
            title="Sao kê ngân hàng"
            loading={txLoading}
          >
            <Table<BankTx>
              columns={txColumns}
              dataSource={txItems}
              rowKey="id"
              size="small"
              pagination={{ pageSize: 15, showTotal: t => `${t} giao dịch` }}
              rowSelection={{
                type: 'radio',
                selectedRowKeys: selectedTx ? [selectedTx.id] : [],
                onChange: (_, rows) => {
                  setSelectedTx(rows[0] ?? null)
                  setSelectedCandidate(null)
                },
              }}
              onRow={record => ({
                onClick: () => {
                  setSelectedTx(record.id === selectedTx?.id ? null : record)
                  setSelectedCandidate(null)
                },
                style: { cursor: 'pointer', background: record.id === selectedTx?.id ? '#e6f4ff' : undefined },
              })}
            />
          </Card>
        </Col>

        {/* Right: Candidates / Actions */}
        <Col span={10}>
          <Card
            size="small"
            title={
              selectedTx
                ? `Chứng từ khớp: ${selectedTx.mo_ta ?? selectedTx.so_tham_chieu ?? '#' + selectedTx.id}`
                : 'Chọn giao dịch bên trái'
            }
            extra={
              selectedTx && (
                <Space>
                  {selectedTx.trang_thai === 'da_doi_soat' && (
                    <Button
                      danger
                      size="small"
                      icon={<CloseCircleOutlined />}
                      loading={unmatchMutation.isPending}
                      onClick={() => unmatchMutation.mutate(selectedTx.id)}
                    >
                      Bỏ khớp
                    </Button>
                  )}
                  {selectedTx.trang_thai === 'chua_doi_soat' && selectedCandidate && (
                    <Button
                      type="primary"
                      size="small"
                      icon={<CheckCircleOutlined />}
                      loading={matchMutation.isPending}
                      onClick={() => matchMutation.mutate({ txId: selectedTx.id, cand: selectedCandidate })}
                    >
                      Khớp
                    </Button>
                  )}
                </Space>
              )
            }
          >
            {!selectedTx && (
              <div style={{ textAlign: 'center', padding: '48px 0', color: '#bbb' }}>
                Chọn một giao dịch để xem chứng từ khớp
              </div>
            )}

            {selectedTx?.trang_thai === 'da_doi_soat' && (
              <div style={{ padding: '24px 0', textAlign: 'center' }}>
                <Tag color="green" style={{ fontSize: 14, padding: '4px 16px' }}>
                  <CheckCircleOutlined /> Đã khớp với {selectedTx.matched_chung_tu_loai} #{selectedTx.matched_chung_tu_id}
                </Tag>
              </div>
            )}

            {selectedTx?.trang_thai === 'chua_doi_soat' && (
              <Table<Candidate>
                columns={candColumns}
                dataSource={candidates ?? []}
                rowKey={candKey}
                size="small"
                loading={candLoading}
                pagination={false}
                rowSelection={{
                  type: 'radio',
                  selectedRowKeys: selectedCandKey ? [selectedCandKey] : [],
                  onChange: (_, rows) => setSelectedCandidate(rows[0] ?? null),
                }}
                onRow={record => ({
                  onClick: () =>
                    setSelectedCandidate(candKey(record) === selectedCandKey ? null : record),
                  style: {
                    cursor: 'pointer',
                    background: candKey(record) === selectedCandKey ? '#f6ffed' : undefined,
                  },
                })}
                locale={{
                  emptyText: 'Không tìm thấy chứng từ khớp',
                }}
              />
            )}
          </Card>
        </Col>
      </Row>
    </PageLayout>
  )
}

import { useState } from 'react'
import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query'
import {
  Button, Card, Col, DatePicker, Descriptions, Drawer, Form, Input, InputNumber,
  message, Modal, Row, Select, Space, Table, Tabs, Tag, Typography,
} from 'antd'
import {
  PlusOutlined, CalendarOutlined, CheckOutlined, StopOutlined,
} from '@ant-design/icons'
import type { ColumnsType } from 'antd/es/table'
import dayjs from 'dayjs'
import client from '../../api/client'
import PageLayout from '../../components/PageLayout'
import { usePhapNhan } from '../../hooks/useMasterData'
import { fmtVND } from '../../utils/exportUtils'

const { Text } = Typography

interface LichTraNo {
  id: number
  ky_so: number
  ngay_den_han: string
  so_tien_goc: number
  so_tien_lai: number
  tong_cong: number
  trang_thai: string
  ngay_tra_thuc: string | null
  so_tien_tra_thuc: number | null
}

interface KheUocVay {
  id: number
  so_khe_uoc: string
  ngay_ky: string
  ngay_hieu_luc: string
  ngay_ket_thuc: string
  to_chuc_cho_vay: string
  so_tien_vay: number
  lai_suat: number
  ky_tinh_lai: string
  phuong_thuc_tra: string
  tai_khoan_nhan: string | null
  tai_san_the_chap: string | null
  ghi_chu: string | null
  trang_thai: string
  phap_nhan_id: number | null
  lich_tra: LichTraNo[]
}

const TRANG_THAI: Record<string, { label: string; color: string }> = {
  hieu_luc: { label: 'Hiệu lực', color: 'blue' },
  da_tra:   { label: 'Đã trả',   color: 'green' },
  huy:      { label: 'Hủy',      color: 'red'   },
}

const TRANG_THAI_KY: Record<string, { label: string; color: string }> = {
  chua_tra: { label: 'Chưa trả', color: 'orange' },
  da_tra:   { label: 'Đã trả',   color: 'green'  },
  qua_han:  { label: 'Quá hạn',  color: 'red'    },
}

const PHUONG_THUC = [
  { value: 'gop_deu',  label: 'Góp đều (Annuity)' },
  { value: 'goc_deu',  label: 'Gốc đều' },
  { value: 'cuoi_ky',  label: 'Cuối kỳ (Bullet)' },
]

const KY_TINH_LAI = [
  { value: 'thang', label: 'Hàng tháng' },
  { value: 'quy',   label: 'Hàng quý' },
  { value: 'nam',   label: 'Hàng năm' },
]

export default function KheUocVayPage() {
  const qc = useQueryClient()
  const { phapNhanList } = usePhapNhan()
  const [filterTrangThai, setFilterTrangThai] = useState<string | undefined>()
  const [filterPhapNhan, setFilterPhapNhan] = useState<number | undefined>()
  const [selected, setSelected] = useState<KheUocVay | null>(null)
  const [createOpen, setCreateOpen] = useState(false)
  const [traNoOpen, setTraNoOpen] = useState(false)
  const [traNoKy, setTraNoKy] = useState<LichTraNo | null>(null)
  const [form] = Form.useForm()
  const [formTraNo] = Form.useForm()

  const { data: list, isLoading } = useQuery({
    queryKey: ['khe-uoc-vay', filterTrangThai, filterPhapNhan],
    queryFn: () => client.get('/accounting/khe-uoc-vay', {
      params: { trang_thai: filterTrangThai, phap_nhan_id: filterPhapNhan },
    }).then(r => r.data),
  })

  const { data: detail, refetch: refetchDetail } = useQuery({
    queryKey: ['khe-uoc-vay-detail', selected?.id],
    queryFn: () =>
      selected ? client.get(`/accounting/khe-uoc-vay/${selected.id}`).then(r => r.data) : null,
    enabled: !!selected,
  })

  const createMutation = useMutation({
    mutationFn: (body: Record<string, unknown>) =>
      client.post('/accounting/khe-uoc-vay', body).then(r => r.data),
    onSuccess: () => {
      message.success('Tạo khế ước thành công')
      qc.invalidateQueries({ queryKey: ['khe-uoc-vay'] })
      setCreateOpen(false)
      form.resetFields()
    },
    onError: () => message.error('Tạo thất bại'),
  })

  const generateMutation = useMutation({
    mutationFn: (id: number) =>
      client.post(`/accounting/khe-uoc-vay/${id}/generate-schedule`).then(r => r.data),
    onSuccess: () => {
      message.success('Đã sinh lịch trả nợ')
      refetchDetail()
      qc.invalidateQueries({ queryKey: ['khe-uoc-vay'] })
    },
    onError: () => message.error('Sinh lịch thất bại'),
  })

  const deleteMutation = useMutation({
    mutationFn: (id: number) =>
      client.delete(`/accounting/khe-uoc-vay/${id}/schedule`).then(r => r.data),
    onSuccess: () => {
      message.success('Đã xóa lịch trả nợ')
      refetchDetail()
    },
    onError: () => message.error('Xóa lịch thất bại'),
  })

  const traNoMutation = useMutation({
    mutationFn: ({ id, body }: { id: number; body: Record<string, unknown> }) =>
      client.patch(`/accounting/khe-uoc-vay/${id}/tra-no`, body).then(r => r.data),
    onSuccess: () => {
      message.success('Đã đánh dấu đã trả')
      setTraNoOpen(false)
      formTraNo.resetFields()
      refetchDetail()
    },
    onError: () => message.error('Thao tác thất bại'),
  })

  const ketThucMutation = useMutation({
    mutationFn: (id: number) =>
      client.patch(`/accounting/khe-uoc-vay/${id}/ket-thuc`).then(r => r.data),
    onSuccess: () => {
      message.success('Đã kết thúc khế ước')
      qc.invalidateQueries({ queryKey: ['khe-uoc-vay'] })
      refetchDetail()
    },
    onError: () => message.error('Thao tác thất bại'),
  })

  const items: KheUocVay[] = list ?? []

  const columns: ColumnsType<KheUocVay> = [
    {
      title: 'Số KU',
      dataIndex: 'so_khe_uoc',
      width: 160,
      render: (v, r) => (
        <a onClick={() => setSelected(r)}>{v}</a>
      ),
    },
    { title: 'Tổ chức cho vay', dataIndex: 'to_chuc_cho_vay', ellipsis: true },
    {
      title: 'Số tiền vay',
      dataIndex: 'so_tien_vay',
      width: 140,
      align: 'right',
      render: v => fmtVND(v),
    },
    {
      title: 'Lãi suất',
      dataIndex: 'lai_suat',
      width: 90,
      align: 'right',
      render: v => `${v}%/năm`,
    },
    {
      title: 'Đến hạn',
      dataIndex: 'ngay_ket_thuc',
      width: 110,
      render: v => dayjs(v).format('DD/MM/YYYY'),
    },
    {
      title: 'Trạng thái',
      dataIndex: 'trang_thai',
      width: 110,
      render: v => {
        const s = TRANG_THAI[v]
        return <Tag color={s?.color}>{s?.label ?? v}</Tag>
      },
    },
    {
      title: '',
      width: 80,
      render: (_, r) => (
        <Button size="small" onClick={() => setSelected(r)}>Chi tiết</Button>
      ),
    },
  ]

  const lichColumns: ColumnsType<LichTraNo> = [
    { title: 'Kỳ', dataIndex: 'ky_so', width: 50, align: 'center' },
    { title: 'Ngày đến hạn', dataIndex: 'ngay_den_han', width: 120, render: v => dayjs(v).format('DD/MM/YYYY') },
    { title: 'Tiền gốc', dataIndex: 'so_tien_goc', align: 'right', render: v => fmtVND(v) },
    { title: 'Tiền lãi', dataIndex: 'so_tien_lai', align: 'right', render: v => fmtVND(v) },
    { title: 'Tổng cộng', dataIndex: 'tong_cong', align: 'right', render: v => <Text strong>{fmtVND(v)}</Text> },
    {
      title: 'Trạng thái',
      dataIndex: 'trang_thai',
      width: 110,
      render: v => {
        const s = TRANG_THAI_KY[v]
        return <Tag color={s?.color}>{s?.label ?? v}</Tag>
      },
    },
    {
      title: '',
      width: 90,
      render: (_, r) =>
        r.trang_thai === 'chua_tra' ? (
          <Button
            size="small"
            type="link"
            onClick={() => {
              setTraNoKy(r)
              setTraNoOpen(true)
            }}
          >
            Trả nợ
          </Button>
        ) : null,
    },
  ]

  const currentDetail: KheUocVay = detail ?? selected

  return (
    <PageLayout
      title="Khế ước đi vay"
      actions={
        <Button type="primary" icon={<PlusOutlined />} onClick={() => setCreateOpen(true)}>
          Tạo khế ước
        </Button>
      }
    >
      {/* Filters */}
      <Card size="small" style={{ marginBottom: 12 }}>
        <Row gutter={12}>
          <Col>
            <Select
              style={{ width: 160 }}
              allowClear
              placeholder="Trạng thái"
              onChange={v => setFilterTrangThai(v)}
              options={Object.entries(TRANG_THAI).map(([k, v]) => ({ value: k, label: v.label }))}
            />
          </Col>
          <Col>
            <Select
              style={{ width: 200 }}
              allowClear
              placeholder="Pháp nhân"
              onChange={v => setFilterPhapNhan(v)}
              options={phapNhanList.map(p => ({ value: p.id, label: p.ten_phap_nhan }))}
            />
          </Col>
        </Row>
      </Card>

      <Table<KheUocVay>
        columns={columns}
        dataSource={items}
        rowKey="id"
        loading={isLoading}
        size="small"
        pagination={{ pageSize: 15, showTotal: t => `${t} khế ước` }}
      />

      {/* Detail Drawer */}
      <Drawer
        title={currentDetail ? `${currentDetail.so_khe_uoc} — ${currentDetail.to_chuc_cho_vay}` : ''}
        open={!!selected}
        onClose={() => setSelected(null)}
        width={760}
        extra={
          currentDetail?.trang_thai === 'hieu_luc' && (
            <Space>
              <Button
                icon={<CalendarOutlined />}
                loading={generateMutation.isPending}
                onClick={() => generateMutation.mutate(currentDetail.id)}
              >
                Sinh lịch
              </Button>
              {(currentDetail.lich_tra?.length ?? 0) > 0 && (
                <Button
                  danger
                  onClick={() =>
                    Modal.confirm({
                      title: 'Xóa lịch trả nợ?',
                      content: 'Toàn bộ lịch trả nợ sẽ bị xóa để tái tạo.',
                      onOk: () => deleteMutation.mutate(currentDetail.id),
                    })
                  }
                >
                  Xóa lịch
                </Button>
              )}
              <Button
                icon={<StopOutlined />}
                onClick={() =>
                  Modal.confirm({
                    title: 'Kết thúc khế ước?',
                    content: 'Trạng thái chuyển sang Đã trả. Không thể hoàn tác.',
                    onOk: () => ketThucMutation.mutate(currentDetail.id),
                  })
                }
              >
                Kết thúc
              </Button>
            </Space>
          )
        }
      >
        {currentDetail && (
          <Tabs
            items={[
              {
                key: 'info',
                label: 'Thông tin',
                children: (
                  <Descriptions bordered size="small" column={2}>
                    <Descriptions.Item label="Số khế ước">{currentDetail.so_khe_uoc}</Descriptions.Item>
                    <Descriptions.Item label="Trạng thái">
                      <Tag color={TRANG_THAI[currentDetail.trang_thai]?.color}>
                        {TRANG_THAI[currentDetail.trang_thai]?.label}
                      </Tag>
                    </Descriptions.Item>
                    <Descriptions.Item label="Tổ chức cho vay" span={2}>{currentDetail.to_chuc_cho_vay}</Descriptions.Item>
                    <Descriptions.Item label="Số tiền vay">{fmtVND(currentDetail.so_tien_vay)}</Descriptions.Item>
                    <Descriptions.Item label="Lãi suất">{currentDetail.lai_suat}%/năm</Descriptions.Item>
                    <Descriptions.Item label="Kỳ tính lãi">
                      {KY_TINH_LAI.find(k => k.value === currentDetail.ky_tinh_lai)?.label}
                    </Descriptions.Item>
                    <Descriptions.Item label="Phương thức trả">
                      {PHUONG_THUC.find(p => p.value === currentDetail.phuong_thuc_tra)?.label}
                    </Descriptions.Item>
                    <Descriptions.Item label="Ngày ký">{dayjs(currentDetail.ngay_ky).format('DD/MM/YYYY')}</Descriptions.Item>
                    <Descriptions.Item label="Ngày hiệu lực">{dayjs(currentDetail.ngay_hieu_luc).format('DD/MM/YYYY')}</Descriptions.Item>
                    <Descriptions.Item label="Ngày kết thúc">{dayjs(currentDetail.ngay_ket_thuc).format('DD/MM/YYYY')}</Descriptions.Item>
                    <Descriptions.Item label="TK nhận tiền">{currentDetail.tai_khoan_nhan ?? '—'}</Descriptions.Item>
                    <Descriptions.Item label="Tài sản thế chấp" span={2}>{currentDetail.tai_san_the_chap ?? '—'}</Descriptions.Item>
                    <Descriptions.Item label="Ghi chú" span={2}>{currentDetail.ghi_chu ?? '—'}</Descriptions.Item>
                  </Descriptions>
                ),
              },
              {
                key: 'schedule',
                label: `Lịch trả nợ (${currentDetail.lich_tra?.length ?? 0})`,
                children: (
                  <Table<LichTraNo>
                    columns={lichColumns}
                    dataSource={currentDetail.lich_tra ?? []}
                    rowKey="id"
                    size="small"
                    pagination={false}
                    summary={rows => {
                      const totalGoc = rows.reduce((s, r) => s + Number(r.so_tien_goc), 0)
                      const totalLai = rows.reduce((s, r) => s + Number(r.so_tien_lai), 0)
                      const totalTong = rows.reduce((s, r) => s + Number(r.tong_cong), 0)
                      return (
                        <Table.Summary.Row style={{ background: '#fafafa', fontWeight: 600 }}>
                          <Table.Summary.Cell index={0} colSpan={2}>Tổng</Table.Summary.Cell>
                          <Table.Summary.Cell index={2} align="right">{fmtVND(totalGoc)}</Table.Summary.Cell>
                          <Table.Summary.Cell index={3} align="right">{fmtVND(totalLai)}</Table.Summary.Cell>
                          <Table.Summary.Cell index={4} align="right">{fmtVND(totalTong)}</Table.Summary.Cell>
                          <Table.Summary.Cell index={5} colSpan={2} />
                        </Table.Summary.Row>
                      )
                    }}
                    locale={{ emptyText: 'Chưa có lịch — nhấn "Sinh lịch" để tạo' }}
                  />
                ),
              },
            ]}
          />
        )}
      </Drawer>

      {/* Create Modal */}
      <Modal
        title="Tạo khế ước đi vay"
        open={createOpen}
        onCancel={() => { setCreateOpen(false); form.resetFields() }}
        onOk={() =>
          form.validateFields().then(v => {
            createMutation.mutate({
              ...v,
              ngay_ky: v.ngay_ky?.format('YYYY-MM-DD'),
              ngay_hieu_luc: v.ngay_hieu_luc?.format('YYYY-MM-DD'),
              ngay_ket_thuc: v.ngay_ket_thuc?.format('YYYY-MM-DD'),
            })
          })
        }
        confirmLoading={createMutation.isPending}
        width={620}
      >
        <Form form={form} layout="vertical">
          <Row gutter={12}>
            <Col span={12}>
              <Form.Item name="to_chuc_cho_vay" label="Tổ chức cho vay" rules={[{ required: true }]}>
                <Input placeholder="Tên ngân hàng / tổ chức" />
              </Form.Item>
            </Col>
            <Col span={12}>
              <Form.Item name="phap_nhan_id" label="Pháp nhân">
                <Select
                  allowClear
                  options={phapNhanList.map(p => ({ value: p.id, label: p.ten_phap_nhan }))}
                />
              </Form.Item>
            </Col>
          </Row>
          <Row gutter={12}>
            <Col span={12}>
              <Form.Item name="so_tien_vay" label="Số tiền vay (đ)" rules={[{ required: true }]}>
                <InputNumber style={{ width: '100%' }} formatter={v => `${v}`.replace(/\B(?=(\d{3})+(?!\d))/g, ',')} min={0} />
              </Form.Item>
            </Col>
            <Col span={6}>
              <Form.Item name="lai_suat" label="Lãi suất (%/năm)" rules={[{ required: true }]}>
                <InputNumber style={{ width: '100%' }} min={0} max={100} step={0.1} />
              </Form.Item>
            </Col>
            <Col span={6}>
              <Form.Item name="ky_tinh_lai" label="Kỳ tính lãi" initialValue="thang">
                <Select options={KY_TINH_LAI} />
              </Form.Item>
            </Col>
          </Row>
          <Row gutter={12}>
            <Col span={8}>
              <Form.Item name="ngay_ky" label="Ngày ký" rules={[{ required: true }]}>
                <DatePicker style={{ width: '100%' }} format="DD/MM/YYYY" />
              </Form.Item>
            </Col>
            <Col span={8}>
              <Form.Item name="ngay_hieu_luc" label="Ngày hiệu lực" rules={[{ required: true }]}>
                <DatePicker style={{ width: '100%' }} format="DD/MM/YYYY" />
              </Form.Item>
            </Col>
            <Col span={8}>
              <Form.Item name="ngay_ket_thuc" label="Ngày kết thúc" rules={[{ required: true }]}>
                <DatePicker style={{ width: '100%' }} format="DD/MM/YYYY" />
              </Form.Item>
            </Col>
          </Row>
          <Row gutter={12}>
            <Col span={12}>
              <Form.Item name="phuong_thuc_tra" label="Phương thức trả" initialValue="gop_deu">
                <Select options={PHUONG_THUC} />
              </Form.Item>
            </Col>
            <Col span={12}>
              <Form.Item name="tai_khoan_nhan" label="TK nhận tiền">
                <Input placeholder="VD: 112.01" />
              </Form.Item>
            </Col>
          </Row>
          <Form.Item name="tai_san_the_chap" label="Tài sản thế chấp">
            <Input.TextArea rows={2} />
          </Form.Item>
          <Form.Item name="ghi_chu" label="Ghi chú">
            <Input.TextArea rows={2} />
          </Form.Item>
        </Form>
      </Modal>

      {/* Tra no modal */}
      <Modal
        title={`Đánh dấu đã trả — Kỳ ${traNoKy?.ky_so}`}
        open={traNoOpen}
        onCancel={() => { setTraNoOpen(false); formTraNo.resetFields() }}
        onOk={() =>
          formTraNo.validateFields().then(v => {
            if (!selected || !traNoKy) return
            traNoMutation.mutate({
              id: selected.id,
              body: {
                ky_so: traNoKy.ky_so,
                ngay_tra_thuc: v.ngay_tra_thuc?.format('YYYY-MM-DD'),
                so_tien_tra_thuc: v.so_tien_tra_thuc,
              },
            })
          })
        }
        confirmLoading={traNoMutation.isPending}
      >
        {traNoKy && (
          <div style={{ marginBottom: 16 }}>
            <Text>Số tiền cần trả: <Text strong>{fmtVND(traNoKy.tong_cong)}</Text></Text>
          </div>
        )}
        <Form form={formTraNo} layout="vertical">
          <Form.Item name="ngay_tra_thuc" label="Ngày trả thực" rules={[{ required: true }]}>
            <DatePicker style={{ width: '100%' }} format="DD/MM/YYYY" defaultValue={dayjs()} />
          </Form.Item>
          <Form.Item name="so_tien_tra_thuc" label="Số tiền trả thực (đ)" rules={[{ required: true }]}>
            <InputNumber
              style={{ width: '100%' }}
              formatter={v => `${v}`.replace(/\B(?=(\d{3})+(?!\d))/g, ',')}
              min={0}
              defaultValue={traNoKy?.tong_cong}
            />
          </Form.Item>
        </Form>
      </Modal>
    </PageLayout>
  )
}

import { useState } from 'react'
import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query'
import {
  Button, Card, Col, DatePicker, Descriptions, Drawer, Form, Input, InputNumber,
  message, Modal, Row, Select, Space, Table, Tabs, Tag, Typography,
} from 'antd'
import {
  PlusOutlined, CalendarOutlined, CheckOutlined, StopOutlined,
} from '@ant-design/icons'
import type { ColumnsType } from 'antd/es/table'
import dayjs from 'dayjs'
import client from '../../api/client'
import PageLayout from '../../components/PageLayout'
import { usePhapNhan } from '../../hooks/useMasterData'
import { fmtVND } from '../../utils/exportUtils'

const { Text } = Typography

interface LichTraNo {
  id: number
  ky_so: number
  ngay_den_han: string
  so_tien_goc: number
  so_tien_lai: number
  tong_cong: number
  trang_thai: string
  ngay_tra_thuc: string | null
  so_tien_tra_thuc: number | null
}

interface KheUocChoVay {
  id: number
  so_khe_uoc: string
  ngay_ky: string
  ngay_hieu_luc: string
  ngay_ket_thuc: string
  to_chuc_di_vay: string
  customer_id: number | null
  so_tien_cho_vay: number
  lai_suat: number
  ky_tinh_lai: string
  phuong_thuc_tra: string
  tai_san_the_chap: string | null
  ghi_chu: string | null
  trang_thai: string
  phap_nhan_id: number | null
  lich_tra: LichTraNo[]
}

const TRANG_THAI: Record<string, { label: string; color: string }> = {
  hieu_luc: { label: 'Hiệu lực', color: 'blue' },
  da_tra:   { label: 'Đã thu',   color: 'green' },
  huy:      { label: 'Hủy',      color: 'red'   },
}

const TRANG_THAI_KY: Record<string, { label: string; color: string }> = {
  chua_tra: { label: 'Chưa thu', color: 'orange' },
  da_tra:   { label: 'Đã thu',   color: 'green'  },
  qua_han:  { label: 'Quá hạn',  color: 'red'    },
}

const PHUONG_THUC = [
  { value: 'gop_deu',  label: 'Góp đều (Annuity)' },
  { value: 'goc_deu',  label: 'Gốc đều' },
  { value: 'cuoi_ky',  label: 'Cuối kỳ (Bullet)' },
]

const KY_TINH_LAI = [
  { value: 'thang', label: 'Hàng tháng' },
  { value: 'quy',   label: 'Hàng quý' },
  { value: 'nam',   label: 'Hàng năm' },
]

export default function KheUocChoVayPage() {
  const qc = useQueryClient()
  const { phapNhanList } = usePhapNhan()
  const [filterTrangThai, setFilterTrangThai] = useState<string | undefined>()
  const [filterPhapNhan, setFilterPhapNhan] = useState<number | undefined>()
  const [selected, setSelected] = useState<KheUocChoVay | null>(null)
  const [createOpen, setCreateOpen] = useState(false)
  const [thuNoOpen, setThuNoOpen] = useState(false)
  const [thuNoKy, setThuNoKy] = useState<LichTraNo | null>(null)
  const [form] = Form.useForm()
  const [formThuNo] = Form.useForm()

  const { data: list, isLoading } = useQuery({
    queryKey: ['khe-uoc-cho-vay', filterTrangThai, filterPhapNhan],
    queryFn: () => client.get('/accounting/khe-uoc-cho-vay', {
      params: { trang_thai: filterTrangThai, phap_nhan_id: filterPhapNhan },
    }).then(r => r.data),
  })

  const { data: detail, refetch: refetchDetail } = useQuery({
    queryKey: ['khe-uoc-cho-vay-detail', selected?.id],
    queryFn: () =>
      selected ? client.get(`/accounting/khe-uoc-cho-vay/${selected.id}`).then(r => r.data) : null,
    enabled: !!selected,
  })

  const createMutation = useMutation({
    mutationFn: (body: Record<string, unknown>) =>
      client.post('/accounting/khe-uoc-cho-vay', body).then(r => r.data),
    onSuccess: () => {
      message.success('Tạo khế ước thành công')
      qc.invalidateQueries({ queryKey: ['khe-uoc-cho-vay'] })
      setCreateOpen(false)
      form.resetFields()
    },
    onError: () => message.error('Tạo thất bại'),
  })

  const generateMutation = useMutation({
    mutationFn: (id: number) =>
      client.post(`/accounting/khe-uoc-cho-vay/${id}/generate-schedule`).then(r => r.data),
    onSuccess: () => {
      message.success('Đã sinh lịch thu nợ')
      refetchDetail()
    },
    onError: () => message.error('Sinh lịch thất bại'),
  })

  const deleteMutation = useMutation({
    mutationFn: (id: number) =>
      client.delete(`/accounting/khe-uoc-cho-vay/${id}/schedule`).then(r => r.data),
    onSuccess: () => {
      message.success('Đã xóa lịch thu nợ')
      refetchDetail()
    },
    onError: () => message.error('Xóa lịch thất bại'),
  })

  const thuNoMutation = useMutation({
    mutationFn: ({ id, body }: { id: number; body: Record<string, unknown> }) =>
      client.patch(`/accounting/khe-uoc-cho-vay/${id}/tra-no`, body).then(r => r.data),
    onSuccess: () => {
      message.success('Đã đánh dấu đã thu')
      setThuNoOpen(false)
      formThuNo.resetFields()
      refetchDetail()
    },
    onError: () => message.error('Thao tác thất bại'),
  })

  const ketThucMutation = useMutation({
    mutationFn: (id: number) =>
      client.patch(`/accounting/khe-uoc-cho-vay/${id}/ket-thuc`).then(r => r.data),
    onSuccess: () => {
      message.success('Đã kết thúc khế ước')
      qc.invalidateQueries({ queryKey: ['khe-uoc-cho-vay'] })
      refetchDetail()
    },
    onError: () => message.error('Thao tác thất bại'),
  })

  const items: KheUocChoVay[] = list ?? []

  const columns: ColumnsType<KheUocChoVay> = [
    {
      title: 'Số KU',
      dataIndex: 'so_khe_uoc',
      width: 160,
      render: (v, r) => <a onClick={() => setSelected(r)}>{v}</a>,
    },
    { title: 'Bên vay', dataIndex: 'to_chuc_di_vay', ellipsis: true },
    {
      title: 'Số tiền cho vay',
      dataIndex: 'so_tien_cho_vay',
      width: 150,
      align: 'right',
      render: v => fmtVND(v),
    },
    {
      title: 'Lãi suất',
      dataIndex: 'lai_suat',
      width: 90,
      align: 'right',
      render: v => `${v}%/năm`,
    },
    {
      title: 'Đến hạn',
      dataIndex: 'ngay_ket_thuc',
      width: 110,
      render: v => dayjs(v).format('DD/MM/YYYY'),
    },
    {
      title: 'Trạng thái',
      dataIndex: 'trang_thai',
      width: 110,
      render: v => {
        const s = TRANG_THAI[v]
        return <Tag color={s?.color}>{s?.label ?? v}</Tag>
      },
    },
    {
      title: '',
      width: 80,
      render: (_, r) => (
        <Button size="small" onClick={() => setSelected(r)}>Chi tiết</Button>
      ),
    },
  ]

  const lichColumns: ColumnsType<LichTraNo> = [
    { title: 'Kỳ', dataIndex: 'ky_so', width: 50, align: 'center' },
    { title: 'Ngày đến hạn', dataIndex: 'ngay_den_han', width: 120, render: v => dayjs(v).format('DD/MM/YYYY') },
    { title: 'Tiền gốc', dataIndex: 'so_tien_goc', align: 'right', render: v => fmtVND(v) },
    { title: 'Tiền lãi', dataIndex: 'so_tien_lai', align: 'right', render: v => fmtVND(v) },
    { title: 'Tổng cộng', dataIndex: 'tong_cong', align: 'right', render: v => <Text strong>{fmtVND(v)}</Text> },
    {
      title: 'Trạng thái',
      dataIndex: 'trang_thai',
      width: 110,
      render: v => {
        const s = TRANG_THAI_KY[v]
        return <Tag color={s?.color}>{s?.label ?? v}</Tag>
      },
    },
    {
      title: '',
      width: 90,
      render: (_, r) =>
        r.trang_thai === 'chua_tra' ? (
          <Button
            size="small"
            type="link"
            onClick={() => {
              setThuNoKy(r)
              setThuNoOpen(true)
            }}
          >
            Thu nợ
          </Button>
        ) : null,
    },
  ]

  const currentDetail: KheUocChoVay = detail ?? selected

  return (
    <PageLayout
      title="Khế ước cho vay"
      actions={
        <Button type="primary" icon={<PlusOutlined />} onClick={() => setCreateOpen(true)}>
          Tạo khế ước
        </Button>
      }
    >
      <Card size="small" style={{ marginBottom: 12 }}>
        <Row gutter={12}>
          <Col>
            <Select
              style={{ width: 160 }}
              allowClear
              placeholder="Trạng thái"
              onChange={v => setFilterTrangThai(v)}
              options={Object.entries(TRANG_THAI).map(([k, v]) => ({ value: k, label: v.label }))}
            />
          </Col>
          <Col>
            <Select
              style={{ width: 200 }}
              allowClear
              placeholder="Pháp nhân"
              onChange={v => setFilterPhapNhan(v)}
              options={phapNhanList.map(p => ({ value: p.id, label: p.ten_phap_nhan }))}
            />
          </Col>
        </Row>
      </Card>

      <Table<KheUocChoVay>
        columns={columns}
        dataSource={items}
        rowKey="id"
        loading={isLoading}
        size="small"
        pagination={{ pageSize: 15, showTotal: t => `${t} khế ước` }}
      />

      {/* Detail Drawer */}
      <Drawer
        title={currentDetail ? `${currentDetail.so_khe_uoc} — ${currentDetail.to_chuc_di_vay}` : ''}
        open={!!selected}
        onClose={() => setSelected(null)}
        width={760}
        extra={
          currentDetail?.trang_thai === 'hieu_luc' && (
            <Space>
              <Button
                icon={<CalendarOutlined />}
                loading={generateMutation.isPending}
                onClick={() => generateMutation.mutate(currentDetail.id)}
              >
                Sinh lịch
              </Button>
              {(currentDetail.lich_tra?.length ?? 0) > 0 && (
                <Button
                  danger
                  onClick={() =>
                    Modal.confirm({
                      title: 'Xóa lịch thu nợ?',
                      content: 'Toàn bộ lịch sẽ bị xóa để tái tạo.',
                      onOk: () => deleteMutation.mutate(currentDetail.id),
                    })
                  }
                >
                  Xóa lịch
                </Button>
              )}
              <Button
                icon={<StopOutlined />}
                onClick={() =>
                  Modal.confirm({
                    title: 'Kết thúc khế ước?',
                    content: 'Trạng thái chuyển sang Đã thu.',
                    onOk: () => ketThucMutation.mutate(currentDetail.id),
                  })
                }
              >
                Kết thúc
              </Button>
            </Space>
          )
        }
      >
        {currentDetail && (
          <Tabs
            items={[
              {
                key: 'info',
                label: 'Thông tin',
                children: (
                  <Descriptions bordered size="small" column={2}>
                    <Descriptions.Item label="Số khế ước">{currentDetail.so_khe_uoc}</Descriptions.Item>
                    <Descriptions.Item label="Trạng thái">
                      <Tag color={TRANG_THAI[currentDetail.trang_thai]?.color}>
                        {TRANG_THAI[currentDetail.trang_thai]?.label}
                      </Tag>
                    </Descriptions.Item>
                    <Descriptions.Item label="Bên vay" span={2}>{currentDetail.to_chuc_di_vay}</Descriptions.Item>
                    <Descriptions.Item label="Số tiền cho vay">{fmtVND(currentDetail.so_tien_cho_vay)}</Descriptions.Item>
                    <Descriptions.Item label="Lãi suất">{currentDetail.lai_suat}%/năm</Descriptions.Item>
                    <Descriptions.Item label="Kỳ tính lãi">
                      {KY_TINH_LAI.find(k => k.value === currentDetail.ky_tinh_lai)?.label}
                    </Descriptions.Item>
                    <Descriptions.Item label="Phương thức thu">
                      {PHUONG_THUC.find(p => p.value === currentDetail.phuong_thuc_tra)?.label}
                    </Descriptions.Item>
                    <Descriptions.Item label="Ngày ký">{dayjs(currentDetail.ngay_ky).format('DD/MM/YYYY')}</Descriptions.Item>
                    <Descriptions.Item label="Ngày hiệu lực">{dayjs(currentDetail.ngay_hieu_luc).format('DD/MM/YYYY')}</Descriptions.Item>
                    <Descriptions.Item label="Ngày kết thúc">{dayjs(currentDetail.ngay_ket_thuc).format('DD/MM/YYYY')}</Descriptions.Item>
                    <Descriptions.Item label="Tài sản thế chấp" span={2}>{currentDetail.tai_san_the_chap ?? '—'}</Descriptions.Item>
                    <Descriptions.Item label="Ghi chú" span={2}>{currentDetail.ghi_chu ?? '—'}</Descriptions.Item>
                  </Descriptions>
                ),
              },
              {
                key: 'schedule',
                label: `Lịch thu nợ (${currentDetail.lich_tra?.length ?? 0})`,
                children: (
                  <Table<LichTraNo>
                    columns={lichColumns}
                    dataSource={currentDetail.lich_tra ?? []}
                    rowKey="id"
                    size="small"
                    pagination={false}
                    summary={rows => {
                      const totalGoc = rows.reduce((s, r) => s + Number(r.so_tien_goc), 0)
                      const totalLai = rows.reduce((s, r) => s + Number(r.so_tien_lai), 0)
                      const totalTong = rows.reduce((s, r) => s + Number(r.tong_cong), 0)
                      return (
                        <Table.Summary.Row style={{ background: '#fafafa', fontWeight: 600 }}>
                          <Table.Summary.Cell index={0} colSpan={2}>Tổng</Table.Summary.Cell>
                          <Table.Summary.Cell index={2} align="right">{fmtVND(totalGoc)}</Table.Summary.Cell>
                          <Table.Summary.Cell index={3} align="right">{fmtVND(totalLai)}</Table.Summary.Cell>
                          <Table.Summary.Cell index={4} align="right">{fmtVND(totalTong)}</Table.Summary.Cell>
                          <Table.Summary.Cell index={5} colSpan={2} />
                        </Table.Summary.Row>
                      )
                    }}
                    locale={{ emptyText: 'Chưa có lịch — nhấn "Sinh lịch" để tạo' }}
                  />
                ),
              },
            ]}
          />
        )}
      </Drawer>

      {/* Create Modal */}
      <Modal
        title="Tạo khế ước cho vay"
        open={createOpen}
        onCancel={() => { setCreateOpen(false); form.resetFields() }}
        onOk={() =>
          form.validateFields().then(v => {
            createMutation.mutate({
              ...v,
              ngay_ky: v.ngay_ky?.format('YYYY-MM-DD'),
              ngay_hieu_luc: v.ngay_hieu_luc?.format('YYYY-MM-DD'),
              ngay_ket_thuc: v.ngay_ket_thuc?.format('YYYY-MM-DD'),
            })
          })
        }
        confirmLoading={createMutation.isPending}
        width={620}
      >
        <Form form={form} layout="vertical">
          <Row gutter={12}>
            <Col span={12}>
              <Form.Item name="to_chuc_di_vay" label="Bên vay" rules={[{ required: true }]}>
                <Input placeholder="Tên cá nhân / tổ chức vay" />
              </Form.Item>
            </Col>
            <Col span={12}>
              <Form.Item name="phap_nhan_id" label="Pháp nhân">
                <Select
                  allowClear
                  options={phapNhanList.map(p => ({ value: p.id, label: p.ten_phap_nhan }))}
                />
              </Form.Item>
            </Col>
          </Row>
          <Row gutter={12}>
            <Col span={12}>
              <Form.Item name="so_tien_cho_vay" label="Số tiền cho vay (đ)" rules={[{ required: true }]}>
                <InputNumber style={{ width: '100%' }} formatter={v => `${v}`.replace(/\B(?=(\d{3})+(?!\d))/g, ',')} min={0} />
              </Form.Item>
            </Col>
            <Col span={6}>
              <Form.Item name="lai_suat" label="Lãi suất (%/năm)" rules={[{ required: true }]}>
                <InputNumber style={{ width: '100%' }} min={0} max={100} step={0.1} />
              </Form.Item>
            </Col>
            <Col span={6}>
              <Form.Item name="ky_tinh_lai" label="Kỳ tính lãi" initialValue="thang">
                <Select options={KY_TINH_LAI} />
              </Form.Item>
            </Col>
          </Row>
          <Row gutter={12}>
            <Col span={8}>
              <Form.Item name="ngay_ky" label="Ngày ký" rules={[{ required: true }]}>
                <DatePicker style={{ width: '100%' }} format="DD/MM/YYYY" />
              </Form.Item>
            </Col>
            <Col span={8}>
              <Form.Item name="ngay_hieu_luc" label="Ngày hiệu lực" rules={[{ required: true }]}>
                <DatePicker style={{ width: '100%' }} format="DD/MM/YYYY" />
              </Form.Item>
            </Col>
            <Col span={8}>
              <Form.Item name="ngay_ket_thuc" label="Ngày kết thúc" rules={[{ required: true }]}>
                <DatePicker style={{ width: '100%' }} format="DD/MM/YYYY" />
              </Form.Item>
            </Col>
          </Row>
          <Row gutter={12}>
            <Col span={12}>
              <Form.Item name="phuong_thuc_tra" label="Phương thức thu" initialValue="gop_deu">
                <Select options={PHUONG_THUC} />
              </Form.Item>
            </Col>
          </Row>
          <Form.Item name="tai_san_the_chap" label="Tài sản thế chấp">
            <Input.TextArea rows={2} />
          </Form.Item>
          <Form.Item name="ghi_chu" label="Ghi chú">
            <Input.TextArea rows={2} />
          </Form.Item>
        </Form>
      </Modal>

      {/* Thu no modal */}
      <Modal
        title={`Đánh dấu đã thu — Kỳ ${thuNoKy?.ky_so}`}
        open={thuNoOpen}
        onCancel={() => { setThuNoOpen(false); formThuNo.resetFields() }}
        onOk={() =>
          formThuNo.validateFields().then(v => {
            if (!selected || !thuNoKy) return
            thuNoMutation.mutate({
              id: selected.id,
              body: {
                ky_so: thuNoKy.ky_so,
                ngay_tra_thuc: v.ngay_tra_thuc?.format('YYYY-MM-DD'),
                so_tien_tra_thuc: v.so_tien_tra_thuc,
              },
            })
          })
        }
        confirmLoading={thuNoMutation.isPending}
      >
        {thuNoKy && (
          <div style={{ marginBottom: 16 }}>
            <Text>Số tiền cần thu: <Text strong>{fmtVND(thuNoKy.tong_cong)}</Text></Text>
          </div>
        )}
        <Form form={formThuNo} layout="vertical">
          <Form.Item name="ngay_tra_thuc" label="Ngày thu thực" rules={[{ required: true }]}>
            <DatePicker style={{ width: '100%' }} format="DD/MM/YYYY" defaultValue={dayjs()} />
          </Form.Item>
          <Form.Item name="so_tien_tra_thuc" label="Số tiền thu thực (đ)" rules={[{ required: true }]}>
            <InputNumber
              style={{ width: '100%' }}
              formatter={v => `${v}`.replace(/\B(?=(\d{3})+(?!\d))/g, ',')}
              min={0}
              defaultValue={thuNoKy?.tong_cong}
            />
          </Form.Item>
        </Form>
      </Modal>
    </PageLayout>
  )
}

import { useState } from 'react'
import { useQuery } from '@tanstack/react-query'
import {
  Card, Col, Radio, Row, Select, Spin, Table, Tag, Typography,
} from 'antd'
import type { ColumnsType } from 'antd/es/table'
import dayjs from 'dayjs'
import {
  ComposedChart, Bar, Line, XAxis, YAxis, CartesianGrid, Tooltip,
  Legend, ResponsiveContainer,
} from 'recharts'
import client from '../../api/client'
import PageLayout from '../../components/PageLayout'
import { usePhapNhan } from '../../hooks/useMasterData'
import { fmtVND } from '../../utils/exportUtils'

const { Text } = Typography

interface ForecastDay {
  ngay: string
  thu: number
  chi: number
  tra_no: number
  thu_no: number
  net: number
  luy_ke: number
}

const PERIOD_OPTIONS = [
  { label: '7 ngày',  value: 7  },
  { label: '14 ngày', value: 14 },
  { label: '30 ngày', value: 30 },
  { label: '60 ngày', value: 60 },
]

const formatBillion = (v: number) => {
  if (Math.abs(v) >= 1_000_000_000) return `${(v / 1_000_000_000).toFixed(1)}tỷ`
  if (Math.abs(v) >= 1_000_000) return `${(v / 1_000_000).toFixed(0)}tr`
  return `${(v / 1_000).toFixed(0)}k`
}

export default function DuBaoDongTienPage() {
  const { phapNhanList } = usePhapNhan()
  const [days, setDays] = useState(30)
  const [phapNhanId, setPhapNhanId] = useState<number | undefined>()

  const { data, isLoading } = useQuery({
    queryKey: ['cash-flow-forecast', days, phapNhanId],
    queryFn: () =>
      client.get('/accounting/cash-flow/forecast', {
        params: { days, phap_nhan_id: phapNhanId },
      }).then(r => r.data),
  })

  const items: ForecastDay[] = data?.items ?? []

  const chartData = items.map(d => ({
    ngay: dayjs(d.ngay).format('DD/MM'),
    thu: Number(d.thu) + Number(d.thu_no),
    chi: -(Number(d.chi) + Number(d.tra_no)),
    luy_ke: Number(d.luy_ke),
  }))

  const tongThu = (Number(data?.tong_thu ?? 0) + Number(data?.tong_thu_no ?? 0))
  const tongChi = (Number(data?.tong_chi ?? 0) + Number(data?.tong_tra_no ?? 0))
  const netTotal = tongThu - tongChi

  const columns: ColumnsType<ForecastDay> = [
    {
      title: 'Ngày',
      dataIndex: 'ngay',
      width: 100,
      render: v => dayjs(v).format('DD/MM/YYYY'),
    },
    {
      title: 'Thu (PT)',
      dataIndex: 'thu',
      align: 'right',
      render: v => Number(v) > 0 ? <Text type="success">{fmtVND(v)}</Text> : null,
    },
    {
      title: 'Thu nợ (CLV)',
      dataIndex: 'thu_no',
      align: 'right',
      render: v => Number(v) > 0 ? <Text type="success">{fmtVND(v)}</Text> : null,
    },
    {
      title: 'Chi (PC)',
      dataIndex: 'chi',
      align: 'right',
      render: v => Number(v) > 0 ? <Text type="danger">{fmtVND(v)}</Text> : null,
    },
    {
      title: 'Trả nợ (KUV)',
      dataIndex: 'tra_no',
      align: 'right',
      render: v => Number(v) > 0 ? <Text type="danger">{fmtVND(v)}</Text> : null,
    },
    {
      title: 'Net ngày',
      dataIndex: 'net',
      align: 'right',
      render: v => {
        const n = Number(v)
        return n !== 0 ? (
          <Text type={n >= 0 ? 'success' : 'danger'}>{fmtVND(n)}</Text>
        ) : null
      },
    },
    {
      title: 'Lũy kế',
      dataIndex: 'luy_ke',
      align: 'right',
      render: v => {
        const n = Number(v)
        return (
          <Text strong type={n < 0 ? 'danger' : undefined}>
            {fmtVND(n)}
          </Text>
        )
      },
    },
  ]

  return (
    <PageLayout title="Dự báo dòng tiền">
      {/* Controls */}
      <Card size="small" style={{ marginBottom: 12 }}>
        <Row gutter={16} align="middle">
          <Col>
            <Radio.Group
              optionType="button"
              buttonStyle="solid"
              value={days}
              onChange={e => setDays(e.target.value)}
              options={PERIOD_OPTIONS}
            />
          </Col>
          {phapNhanList.length > 1 && (
            <Col>
              <Select
                style={{ width: 220 }}
                allowClear
                placeholder="Tất cả pháp nhân"
                onChange={v => setPhapNhanId(v)}
                options={phapNhanList.map(p => ({ value: p.id, label: p.ten_phap_nhan }))}
              />
            </Col>
          )}
        </Row>
      </Card>

      {/* Summary cards */}
      <Row gutter={12} style={{ marginBottom: 12 }}>
        <Col span={6}>
          <Card size="small" style={{ textAlign: 'center' }}>
            <div style={{ color: '#888', fontSize: 12 }}>Tổng thu dự kiến</div>
            <div style={{ fontSize: 18, fontWeight: 700, color: '#3f8600' }}>{fmtVND(tongThu)}</div>
          </Card>
        </Col>
        <Col span={6}>
          <Card size="small" style={{ textAlign: 'center' }}>
            <div style={{ color: '#888', fontSize: 12 }}>Tổng chi dự kiến</div>
            <div style={{ fontSize: 18, fontWeight: 700, color: '#cf1322' }}>{fmtVND(tongChi)}</div>
          </Card>
        </Col>
        <Col span={6}>
          <Card size="small" style={{ textAlign: 'center' }}>
            <div style={{ color: '#888', fontSize: 12 }}>Net dòng tiền</div>
            <div style={{ fontSize: 18, fontWeight: 700, color: netTotal >= 0 ? '#3f8600' : '#cf1322' }}>
              {fmtVND(netTotal)}
            </div>
          </Card>
        </Col>
        <Col span={6}>
          <Card size="small" style={{ textAlign: 'center' }}>
            <div style={{ color: '#888', fontSize: 12 }}>Lũy kế cuối kỳ</div>
            <div style={{ fontSize: 18, fontWeight: 700, color: Number(items.at(-1)?.luy_ke ?? 0) < 0 ? '#cf1322' : '#3f8600' }}>
              {fmtVND(Number(items.at(-1)?.luy_ke ?? 0))}
            </div>
          </Card>
        </Col>
      </Row>

      {/* Chart */}
      <Card size="small" style={{ marginBottom: 12 }}>
        {isLoading ? (
          <div style={{ textAlign: 'center', padding: 40 }}><Spin /></div>
        ) : items.length === 0 ? (
          <div style={{ textAlign: 'center', padding: 40, color: '#bbb' }}>
            Không có dữ liệu dự báo trong kỳ này
          </div>
        ) : (
          <ResponsiveContainer width="100%" height={300}>
            <ComposedChart data={chartData} margin={{ top: 8, right: 16, left: 8, bottom: 0 }}>
              <CartesianGrid strokeDasharray="3 3" stroke="#f0f0f0" />
              <XAxis dataKey="ngay" tick={{ fontSize: 11 }} />
              <YAxis
                tickFormatter={formatBillion}
                tick={{ fontSize: 11 }}
                width={56}
              />
              <Tooltip
                formatter={(value: number, name: string) => [
                  fmtVND(Math.abs(value)),
                  name === 'thu' ? 'Thu' : name === 'chi' ? 'Chi' : 'Lũy kế',
                ]}
                labelFormatter={l => `Ngày ${l}`}
              />
              <Legend
                formatter={v => v === 'thu' ? 'Thu' : v === 'chi' ? 'Chi' : 'Lũy kế'}
              />
              <Bar dataKey="thu" fill="#52c41a" radius={[2, 2, 0, 0]} name="thu" />
              <Bar dataKey="chi" fill="#ff4d4f" radius={[2, 2, 0, 0]} name="chi" />
              <Line
                type="monotone"
                dataKey="luy_ke"
                stroke="#1677ff"
                strokeWidth={2}
                dot={false}
                name="luy_ke"
              />
            </ComposedChart>
          </ResponsiveContainer>
        )}
      </Card>

      {/* Table */}
      <Table<ForecastDay>
        columns={columns}
        dataSource={items}
        rowKey="ngay"
        size="small"
        loading={isLoading}
        pagination={false}
        rowClassName={r => Number(r.luy_ke) < 0 ? 'ant-table-row-danger' : ''}
        summary={() => {
          if (!items.length) return null
          return (
            <Table.Summary.Row style={{ background: '#fafafa', fontWeight: 700 }}>
              <Table.Summary.Cell index={0}>Tổng</Table.Summary.Cell>
              <Table.Summary.Cell index={1} align="right">
                <Text type="success">{fmtVND(data?.tong_thu ?? 0)}</Text>
              </Table.Summary.Cell>
              <Table.Summary.Cell index={2} align="right">
                <Text type="success">{fmtVND(data?.tong_thu_no ?? 0)}</Text>
              </Table.Summary.Cell>
              <Table.Summary.Cell index={3} align="right">
                <Text type="danger">{fmtVND(data?.tong_chi ?? 0)}</Text>
              </Table.Summary.Cell>
              <Table.Summary.Cell index={4} align="right">
                <Text type="danger">{fmtVND(data?.tong_tra_no ?? 0)}</Text>
              </Table.Summary.Cell>
              <Table.Summary.Cell index={5} align="right">
                <Text type={netTotal >= 0 ? 'success' : 'danger'}>{fmtVND(netTotal)}</Text>
              </Table.Summary.Cell>
              <Table.Summary.Cell index={6} />
            </Table.Summary.Row>
          )
        }}
      />

      <style>{`
        .ant-table-row-danger td { background: #fff2f0 !important; }
      `}</style>
    </PageLayout>
  )
}

